# Embergrave Weather System Implementation

I'll implement the weather system for Embergrave following the design requirements. This includes adding weather attributes to levels, implementing rain effects on ember pickups and gliding, and tracking rain levels per region.

## Changes to Level Data Structure

First, I need to modify the level data structure to include weather information:

```python
# level.py
class Level:
    def __init__(self, name, region, weather="clear", checkpoints=None):
        self.name = name
        self.region = region
        self.weather = weather  # "clear" or "rain"
        self.checkpoints = checkpoints or []
        self.ember_pickups = []  # ember pickup data for this level

    def is_rainy(self):
        return self.weather == "rain"
```

## Weather System Implementation

```python
# weather_system.py
class WeatherSystem:
    def __init__(self):
        self.region_rain_counts = {
            "caverns": 0,
            "fault_lines": 0,
            "hot_springs": 0,
            "summit": 0
        }

    def add_rain_level(self, region):
        """Increment the rain level count for a region"""
        if region in self.region_rain_counts:
            self.region_rain_counts[region] += 1

    def get_rain_count(self, region):
        """Get the number of rain levels in a region"""
        return self.region_rain_counts.get(region, 0)

    def get_all_rain_counts(self):
        """Get all region rain counts"""
        return self.region_rain_counts.copy()
```

## Ember Pickup System Modification

```python
# ember.py
class EmberPickup:
    def __init__(self, value, position):
        self.value = value  # base value (e.g., 3, 4)
        self.position = position
        self.collected = False

    def get_effective_value(self, level_weather):
        """Calculate the effective ember value based on weather"""
        if level_weather == "rain":
            return max(0, int(self.value / 2))  # Half value, rounded down
        return self.value

class EmberSystem:
    def __init__(self):
        self.current_ember = 0
        self.max_ember = 100

    def collect_ember(self, pickup, level_weather):
        """Collect ember from a pickup, applying weather effects"""
        effective_value = pickup.get_effective_value(level_weather)

        # If it's rain and the pickup would give 0, show fizzle effect
        if level_weather == "rain" and effective_value == 0 and pickup.value > 0:
            self._show_fizzle_effect()

        self.current_ember = min(self.max_ember, self.current_ember + effective_value)
        pickup.collected = True

    def _show_fizzle_effect(self):
        """Show visual effect when ember pickup fizzes in rain"""
        # This would trigger a visual/auditory effect
        pass
```

## Moth Physics and Gliding System

```python
# moth.py
class Moth:
    def __init__(self):
        self.position = (0, 0)
        self.velocity = (0, 0)
        self.is_gliding = False
        self.ember = 100
        self.max_ember = 100

    def start_glide(self):
        """Start gliding"""
        self.is_gliding = True

    def stop_glide(self):
        """Stop gliding"""
        self.is_gliding = False

    def update_glide(self, level_weather):
        """Update ember consumption during glide"""
        if self.is_gliding:
            # Normal ember drain rate
            drain_rate = 1.0

            # If it's raining, increase drain rate by 50%
            if level_weather == "rain":
                drain_rate *= 1.5

            self.ember = max(0, self.ember - drain_rate)
```

## Level Manager Integration

```python
# level_manager.py
class LevelManager:
    def __init__(self):
        self.weather_system = WeatherSystem()
        self.levels = []

    def load_level(self, level_data):
        """Load a level with weather information"""
        # Create level from data
        level = Level(
            name=level_data.get("name"),
            region=level_data.get("region"),
            weather=level_data.get("weather", "clear"),  # Default to clear
            checkpoints=level_data.get("checkpoints", [])
        )

        # Track rain levels per region
        if level.weather == "rain":
            self.weather_system.add_rain_level(level.region)

        self.levels.append(level)
        return level

    def get_region_rain_counts(self):
        """Get the rain counts for all regions"""
        return self.weather_system.get_all_rain_counts()
```

## Game State Integration

```python
# game_state.py
class GameState:
    def __init__(self):
        self.level_manager = LevelManager()
        self.moth = Moth()
        self.current_level = None

    def enter_level(self, level_data):
        """Enter a new level"""
        self.current_level = self.level_manager.load_level(level_data)

    def update(self):
        """Update game state including weather effects"""
        if self.current_level and self.current_level.is_rainy():
            # Apply weather effects
            self.moth.update_glide(self.current_level.weather)

    def collect_ember(self, pickup):
        """Collect ember from a pickup in the current level"""
        if self.current_level:
            self.level_manager.ember_system.collect_ember(
                pickup, 
                self.current_level.weather
            )
```

